const patterns = [
  { regex: /\b\d{3}-?\d{2}-?\d{4}\b/g, token: "[SSN-REDACTED]" },
  { regex: /\b\d{2}-\d{7}\b/g, token: "[EIN-REDACTED]" },
  { regex: /\b\d{8,17}\b/g, token: "[ACCOUNT-REDACTED]" },
  { regex: /\b\d{9}\b/g, token: "[ROUTING-REDACTED]" },
  { regex: /\b(?:\d[ -]*?){13,16}\b/g, token: "[CARD-REDACTED]" },
];

return $input.all().map(item => {
  let safeSubject = item.json.subject || '';
  let safeBody = item.json.text || item.json.html || '';

  for (const p of patterns) {
    safeSubject = safeSubject.replace(p.regex, p.token);
    safeBody = safeBody.replace(p.regex, p.token);
  }

  const fromAddr = item.json.from?.value?.[0]?.address || item.json.from || '';
  const domain = (fromAddr.split('@')[1] || '').toLowerCase();

  return {
    json: {
      ...item.json,
      sender_email: fromAddr.toLowerCase(),
      sender_domain: domain,
      subject_original: item.json.subject,
      body_original: item.json.text,
      subject: safeSubject,
      body: safeBody,
    }
  };
});

const email = $('2. Redact Sensitive Data').first().json;
const orgResult = $('2b-i. Lookup Karbon Organization').first().json;
const contactResult = $('2b-ii. Lookup Karbon Contact').first().json;

const orgMatch = orgResult?.value?.[0];
const contactMatch = contactResult?.value?.[0];

let clientKey = null;
let clientType = null;
let clientFound = false;

if (orgMatch) {
  clientKey = orgMatch.OrganizationKey;
  clientType = 'Organization';
  clientFound = true;
} else if (contactMatch) {
  clientKey = contactMatch.ContactKey;
  clientType = 'Contact';
  clientFound = true;
}

return [{
  json: {
    ...email,
    client_key: clientKey,
    client_type: clientType,
    client_found: clientFound,
  }
}];

const workItem = $input.first().json;
const classification = $('4. AI Classify and Match').first().json;

const existingDescription = workItem.Description || '';
const timestamp = new Date().toISOString();
const aiNote = `[AI Triage ${timestamp}] Auto-assigned. Reasoning: ${classification.output.reasoning} (Category: ${classification.output.suggested_category})`;

const newDescription = existingDescription
  ? existingDescription + '\n\n' + aiNote
  : aiNote;

return [{
  json: {
    ...classification,
    WorkItemKey: workItem.WorkItemKey,
    new_description: newDescription
  }
}];

